const { execSync } = require('child_process');
const fs = require('fs');
const data = $json.text;

// Generate LaTeX
const latex = `\\documentclass{article}\\begin{document} ${data} \\end{document}`;
fs.writeFileSync('/workspace/resume.tex', latex);

// Compile
try {
  execSync('docker exec gensyncai_latex pdflatex -interaction=nonstopmode /workspace/resume.tex');
} catch (e) {}

// Return PDF Binary
const pdfBuffer = fs.readFileSync('/workspace/resume.pdf');
return { binary: { data: { data: pdfBuffer.toString('base64'), fileName: 'resume.pdf', mimeType: 'application/pdf' } } };
